 namespace WPAICG\Chat\Storage\GetterMethods; if (!defined('ABSPATH')) { exit; } function get_trigger_config_logic(int $bot_id, callable $get_meta_fn): array { $settings = []; $trigger_meta_key = '_aipkit_chatbot_triggers'; $trigger_storage_class_name = '\WPAICG\Lib\Chat\Triggers\AIPKit_Trigger_Storage'; if (class_exists($trigger_storage_class_name)) { $trigger_meta_key = $trigger_storage_class_name::META_KEY; } $triggers_json_string = $get_meta_fn($trigger_meta_key, '[]'); if (!is_string($triggers_json_string) || trim($triggers_json_string) === '') { $triggers_json_string = '[]'; } $decoded = json_decode($triggers_json_string, true); if (json_last_error() !== JSON_ERROR_NONE || !is_array($decoded)) { $repaired = preg_replace_callback( '/("body_template"\s*:\s*")(.+?)(")\s*,\s*"timeout_seconds"/s', static function (array $matches): string { $value = $matches[2]; $value = str_replace('\\', '\\\\', $value); $value = str_replace('"', '\\"', $value); return $matches[1] . $value . $matches[3] . ', "timeout_seconds"'; }, $triggers_json_string, -1, $repair_count ); if (!empty($repair_count)) { $decoded = json_decode($repaired, true); if (json_last_error() === JSON_ERROR_NONE && is_array($decoded)) { $triggers_json_string = $repaired; } } } if (json_last_error() === JSON_ERROR_NONE && is_array($decoded)) { $settings['triggers_json'] = wp_json_encode($decoded, JSON_UNESCAPED_UNICODE | JSON_UNESCAPED_SLASHES); } else { $settings['triggers_json'] = '[]'; } return $settings; } 